/**
 * @param {number[][]} points
 * @param {number[]} target
 * @return {number}
 */
function solve(points, target) {
    // Helper function to convert a point array [x, y, z] to a unique string key "x,y,z"
    const pointToKey = (p) => `${p[0]},${p[1]},${p[2]}`;

    // Helper function to convert a string key back to a point array
    const keyToPoint = (key) => key.split(',').map(Number);

    const targetKey = pointToKey(target);

    // S stores all unique points generated so far: Map<string_key, point_array>
    let S = new Map(); 

    // Initialize S with initial points (Generation 0)
    for (const p of points) {
        const key = pointToKey(p);
        S.set(key, p);
    }

    // Check Generation 0
    if (S.has(targetKey)) {
        return 0;
    }

    let k = 0;
    let hasNewPoints = true;

    // Loop simulation k=1, 2, 3, ...
    while (hasNewPoints) {
        k++;
        hasNewPoints = false;

        // Convert map values to an array of points for easy indexed iteration
        const availablePoints = Array.from(S.values());
        const N = availablePoints.length;

        // Set to store keys of points newly generated in this step k
        const newlyGeneratedKeys = new Set();

        // Iterate over all unique pairs (a, b) from the current set S
        for (let i = 0; i < N; i++) {
            const a = availablePoints[i];
            for (let j = i + 1; j < N; j++) {
                const b = availablePoints[j];

                // Calculate c = average_floor(a, b)
                const c = [
                    Math.floor((a[0] + b[0]) / 2),
                    Math.floor((a[1] + b[1]) / 2),
                    Math.floor((a[2] + b[2]) / 2)
                ];

                const cKey = pointToKey(c);

                // Only consider points that are genuinely new to the cumulative set S
                if (!S.has(cKey)) {

                    newlyGeneratedKeys.add(cKey);

                    // Check if this new point is the target
                    if (cKey === targetKey) {
                        return k;
                    }
                }
            }
        }

        // If no new points were generated in this iteration, we stop.
        if (newlyGeneratedKeys.size === 0) {
            return -1;
        }

        // Update S with all newly generated points
        for (const key of newlyGeneratedKeys) {
            const p = keyToPoint(key);
            S.set(key, p);
        }

        hasNewPoints = true;
    }

    // Should be unreachable if logic is correct, but included for safety
    return -1;
}

