struct Point {
    long long x, y, z;

    // Overload < operator for use in std::set
    bool operator<(const Point& other) const {
        if (x != other.x) return x < other.x;
        if (y != other.y) return y < other.y;
        return z < other.z;
    }

    // Overload == operator for easy comparison
    bool operator==(const Point& other) const {
        return x == other.x && y == other.y && z == other.z;
    }
};

long long solve(std::vector<std::vector<long long>> points, std::vector<long long> target) {
    // Convert target vector to Point struct
    Point target_p = {target[0], target[1], target[2]};

    // S stores all unique points generated so far (Generation 0 up to k-1)
    std::set<Point> S;

    // 1. Initialize S with initial points (Generation 0)
    for (const auto& p_vec : points) {
        S.insert({p_vec[0], p_vec[1], p_vec[2]});
    }

    // 2. Check Generation 0
    if (S.count(target_p)) {
        return 0;
    }

    long long k = 0;

    // Start simulation for k = 1, 2, 3, ...
    while (true) {
        k++;

        // We need a temporary set to store points newly generated in this step k,
        // to avoid using newly generated points in the same step k calculation.
        std::set<Point> newly_generated_in_k;

        // Convert S into a vector for indexed iteration to handle pairs easily
        std::vector<Point> current_points(S.begin(), S.end());
        int N = current_points.size();

        bool found_new_point = false;

        // Iterate over all unique pairs (a, b) from the current set S
        for (int i = 0; i < N; ++i) {
            for (int j = i + 1; j < N; ++j) {
                const Point& a = current_points[i];
                const Point& b = current_points[j];

                // Calculate c = average_floor(a, b)
                Point c = {
                    (a.x + b.x) / 2, // Integer division in C++ performs floor for positive numbers
                    (a.y + b.y) / 2,
                    (a.z + b.z) / 2
                };

                // Check if c is already known (in S or already generated in this step k)
                if (!S.count(c) && !newly_generated_in_k.count(c)) {

                    newly_generated_in_k.insert(c);
                    found_new_point = true;

                    // Check if this new point is the target
                    if (c == target_p) {
                        return k;
                    }
                }
            }
        }

        // If no new unique points were generated in this iteration, we stop.
        if (!found_new_point) {
            return -1;
        }

        // Update S with all newly generated points
        for (const auto& p : newly_generated_in_k) {
            S.insert(p);
        }
    }
}

